// src/components/common/Header.jsx
import React, { useState, useEffect, useRef } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import './Header.css';

const Header = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const dropdownRef = useRef(null);

  const [user, setUser] = useState(null);
  const [showDropdown, setShowDropdown] = useState(false);
  const [scrolled, setScrolled] = useState(false);

  // scroll effect
  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 40);
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  // load user
  useEffect(() => {
    try {
      const data = localStorage.getItem('user');
      if (data) setUser(JSON.parse(data));
    } catch {}
  }, []);

  // click outside dropdown
  useEffect(() => {
    const close = e => {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target)) {
        setShowDropdown(false);
      }
    };
    document.addEventListener('mousedown', close);
    return () => document.removeEventListener('mousedown', close);
  }, []);

  const logout = () => {
    localStorage.clear();
    setUser(null);
    navigate('/');
  };

  return (
    <header className={`header ${scrolled ? 'scrolled' : ''}`}>
      <div className="container header-row">

        <Link to="/" className="logo">
          <span className="logo-title">Ceylon Tours</span>
        </Link>

        <nav className="nav">

          <Link to="/" className={`nav-link ${location.pathname==='/'?'active':''}`}>Home</Link>
          <Link to="/tours" className={`nav-link ${location.pathname==='/tours'?'active':''}`}>Tours</Link>

          {/* always keep login visible */}
          {!user && (
            <Link to="/login" className="login-btn">
              Login
            </Link>
          )}

          {user && (
            <div className="user-wrap" ref={dropdownRef}>
              <button
                className="user-btn"
                onClick={() => setShowDropdown(v => !v)}
              >
                {user.name?.split(' ')[0]}
              </button>

              {showDropdown && (
                <div className="dropdown">
                  <Link to="/account" onClick={()=>setShowDropdown(false)}>Account</Link>
                  <button onClick={logout}>Logout</button>
                </div>
              )}
            </div>
          )}

        </nav>

      </div>
    </header>
  );
};

export default Header;
